/** Petshop Probe Slot v10 (audit: pragma mode + options) */
add_action('wp_loaded', function(){
  if ( ($_GET['ps_probe'] ?? '') !== 'ps2026' ) return;
  global $wpdb;
  $out = array('ts'=>gmdate('c'));
  // 1. pragma plugin files
  $dir = WP_PLUGIN_DIR.'/petshop-pragma';
  $out['files'] = array();
  if(is_dir($dir)){
    foreach (glob($dir.'/*.php') as $f){ $out['files'][] = basename($f).' ('.filesize($f).'b)'; }
    foreach (glob($dir.'/includes/*.php') as $f){ $out['files'][] = 'includes/'.basename($f).' ('.filesize($f).'b)'; }
  }
  // 2. grep mode-related lines from all pragma php files
  $lines = array();
  $all = array_merge(glob($dir.'/*.php')?:array(), glob($dir.'/includes/*.php')?:array());
  foreach($all as $f){
    $c = file_get_contents($f);
    foreach(explode("\n",$c) as $i=>$ln){
      if(preg_match('/production|test_mode|dry|audac|recipient|wp_mail|PRAGMA_.*(MODE|LIVE|TEST)|define\(/i',$ln)){
        $t = trim($ln);
        if(strlen($t)>2 && strlen($t)<220) $lines[] = basename($f).':'.($i+1).' '.$t;
      }
    }
  }
  $out['mode_lines'] = array_slice($lines,0,40);
  // 3. options like pragma
  $opts = $wpdb->get_results("SELECT option_name, option_value FROM {$wpdb->options} WHERE option_name LIKE '%pragma%'", ARRAY_A);
  foreach($opts as &$o){ if(strlen($o['option_value'])>300) $o['option_value']=substr($o['option_value'],0,300).'...'; }
  $out['options'] = $opts;
  // 4. cron next run for pragma hook
  $out['next_pragma_cron'] = wp_next_scheduled('petshop_pragma_monthly_export') ? gmdate('c', wp_next_scheduled('petshop_pragma_monthly_export')) : 'none';
  header('Content-Type: application/json');
  echo wp_json_encode($out);
  exit;
}, 1);
